const express = require('express');
const axios = require('axios');
const app = express();
const PORT = process.env.PORT || 3000;

// Middleware to parse JSON
app.use(express.json());

// In-memory storage for API keys (use database in production)
const validApiKeys = new Set(['key123', 'key456', 'key789']);

// Logging middleware
app.use((req, res, next) => {
  console.log(`[${new Date().toISOString()}] ${req.method} ${req.url} - API Key: ${req.query.api_key || 'none'}`);
  next();
});

// Authentication middleware
const authenticateApiKey = (req, res, next) => {
  const apiKey = req.query.api_key;
  
  if (!apiKey) {
    return res.status(401).json({ error: 'API key required' });
  }
  
  if (!validApiKeys.has(apiKey)) {
    return res.status(403).json({ error: 'Invalid API key' });
  }
  
  req.apiKey = apiKey;
  next();
};

// Proxy middleware
const proxyMiddleware = async (req, res) => {
  try {
    const targetUrl = `https://api.example.com${req.url}`;
    
    // Forward the API key in headers
    const headers = {
      ...req.headers,
      'x-api-key': req.apiKey
    };
    
    // Remove api_key from headers to prevent leakage
    delete headers['api_key'];
    
    const response = await axios({
      method: req.method,
      url: targetUrl,
      headers: headers,
      data: req.body,
      timeout: 10000
    });
    
    res.status(response.status).json(response.data);
  } catch (error) {
    console.error('Proxy error:', error.message);
    if (error.response) {
      res.status(error.response.status).json(error.response.data);
    } else {
      res.status(500).json({ error: 'Internal server error' });
    }
  }
};

// Routes
app.all('/api/*', authenticateApiKey, proxyMiddleware);

app.listen(PORT, () => {
  console.log(`API Gateway running on port ${PORT}`);
});